class Solution:
    def numberOfUniqueGoodSubsequences(self, binary):
        n = len(binary)
        seen = set()
        for mask in range(1, 1 << n):
            chars = [binary[i] for i in range(n) if mask & (1 << i)]
            if chars[0] == '0' and len(chars) > 1:
                continue
            seen.add(''.join(chars))
        return len(seen) % (10 ** 9 + 7)

solutions.python:
class Solution:
    def numberOfUniqueGoodSubsequences(self, binary):
        MOD = 10 ** 9 + 7
        ends0 = 0
        ends1 = 0
        has_zero = 0
        for c in binary:
            if c == '1':
                ends1 = (ends0 + ends1 + 1) % MOD
            else:
                ends0 = (ends0 + ends1) % MOD
                has_zero = 1
        return (ends0 + ends1 + has_zero) % MOD

