var numberOfUniqueGoodSubsequences = function(binary) {
    const MOD = 1000000007;
    let ends0 = 0, ends1 = 0, hasZero = 0;
    for (const c of binary) {
        if (c === '1') {
            ends1 = (ends0 + ends1 + 1) % MOD;
        } else {
            ends0 = (ends0 + ends1) % MOD;
            hasZero = 1;
        }
    }
    return (ends0 + ends1 + hasZero) % MOD;
};
